 1	import React, { FC } from 'react';
 2	
 3	import { useInstanceTypeVMStore } from '@catalog/CreateFromInstanceTypes/state/useInstanceTypeVMStore';
 4	import AddBootableVolumeModal from '@kubevirt-utils/components/AddBootableVolumeModal/AddBootableVolumeModal';
 5	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import useCanCreateBootableVolume from '@kubevirt-utils/resources/bootableresources/hooks/useCanCreateBootableVolume';
 8	import { Button, ButtonVariant } from '@patternfly/react-core';
 9	
10	export type AddBootableVolumeButtonProps = {
11	  loadError: Error;
12	};
13	
14	const AddBootableVolumeButton: FC<AddBootableVolumeButtonProps> = ({ loadError }) => {
15	  const { t } = useKubevirtTranslation();
16	  const { createModal } = useModal();
17	  const { onSelectCreatedVolume, volumeListNamespace } = useInstanceTypeVMStore();
18	
19	  const { canCreateDS, canCreatePVC } = useCanCreateBootableVolume(volumeListNamespace);
20	  const canCreate = canCreateDS || canCreatePVC;
21	
22	  return (
23	    <Button
24	      onClick={() =>
25	        createModal((props) => (
26	          <AddBootableVolumeModal onCreateVolume={onSelectCreatedVolume} {...props} />
27	        ))
28	      }
29	      id="tour-step-add-volume"
30	      isDisabled={!!loadError || !canCreate}
31	      variant={ButtonVariant.secondary}
32	    >
33	      {t('Add volume')}
34	    </Button>
35	  );
36	};
37	
38	export default AddBootableVolumeButton;

